    return JSON.stringify({
      pos: s.player_position,
      hp: s.player_stats,
      entities: s.nearby_entities.filter(e => e.quest_npc || e.has_achievement || e.type === 4).map(e => ({name:e.name, type:e.type, x:e.x, y:e.y, dist:e.distance, on_screen:e.on_screen, cx:e.click_x, cy:e.click_y, quest:e.quest_npc}))
    });
  });
  return state;
}

