async (page) => {
  // Force warp - try multiple methods
  await page.evaluate(() => {
    try { window.game.menu.warp.show(); } catch(e) {}
  });
  await page.waitForTimeout(1000);

  // Check if warp UI is visible
  const warpVisible = await page.evaluate(() => {
    const warp = document.getElementById('warp0') || document.querySelector('[id*="warp"]');
    return warp ? warp.offsetParent !== null : false;
  });

  if (warpVisible) {
    await page.evaluate(() => document.getElementById('warp0').click());
  } else {
    // Try keyboard shortcut or direct teleport
    await page.evaluate(() => {
      try {
        // Try direct warp via game API
        window.game.teleport(188, 157);
      } catch(e) {
        console.log('teleport failed: ' + e);
